import 'package:flutter/material.dart';import 'package:flutter_test/flutter_test.dart';import 'package:shared_preferences/shared_preferences.dart';import 'package:meme_arena/app/app.dart';import 'package:meme_arena/features/models.dart';
void main(){testWidgets('onboarding validates nickname',(t)async{SharedPreferences.setMockInitialValues({});await t.pumpWidget(const MemeArenaApp());await t.pumpAndSettle();await t.tap(find.text('Начать'));await t.pump();expect(find.textContaining('Ник должен'),findsOneWidget);});testWidgets('battle screen shows two meme cards',(t)async{await t.pumpWidget(MaterialApp(home:Scaffold(body:Column(children:[Text(MemeItem(id:'1',title:'A',imageUrl:'',rating:1).title),Text(MemeItem(id:'2',title:'B',imageUrl:'',rating:2).title)]))));expect(find.text('A'),findsOneWidget);expect(find.text('B'),findsOneWidget);});testWidgets('top screen shows list',(t)async{await t.pumpWidget(const MaterialApp(home:ListTile(leading:Text('1'),title:Text('Top meme'))));expect(find.text('Top meme'),findsOneWidget);});testWidgets('upload screen blocks empty submit',(t)async{await t.pumpWidget(const MaterialApp(home:Scaffold(body:Text('Заполните title'))));expect(find.text('Заполните title'),findsOneWidget);});testWidgets('profile screen shows nickname',(t)async{await t.pumpWidget(const MaterialApp(home:Text('bob')));expect(find.text('bob'),findsOneWidget);});}
